   217→
   218→  // Keyboard shortcut for search (Cmd+K)
   219→  useEffect(() => {
   220→    const handleKeyDown = (e: KeyboardEvent) => {
   221→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
   222→        e.preventDefault();
