   255→    if (!folderToDelete) {
   256→      log.warn('Folder not found', { folderId: selectedFolderId });
   257→      return;
   258→    }
   259→
   260→    const notesToDelete = Object.values(notesObj).filter(note => note.folderId === selectedFolderId);
   261→    const noteCount = notesToDelete.length;
   262→
   263→    // Delete all notes in this folder (without undo since folder undo will handle it)
   264→    // We need to temporarily bypass the undo system for individual notes
   265→    notesToDelete.forEach(note => {
   266→      // Call the store action directly without triggering undo
   267→      useNotesStore.setState((state) => {
   268→        const { [note.id]: deleted, ...remainingNotes } = state.notes;
