   691→/**
   692→ * Notes List Component
   693→ */
   694→const NotesList: React.FC<{
   695→  activeTags: string[];
   696→  onOpenTemplateLibrary: () => void;
   697→  onOpenExportModal: () => void;
   698→}> = ({ activeTags, onOpenTemplateLibrary, onOpenExportModal }) => {
   699→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   700→  // Get raw notes and store config (stable references)
   701→  const notesObj = useNotesStore((state) => state.notes);
   702→  const sortConfig = useNotesStore((state) => state.sortConfig);
   703→  const filter = useNotesStore((state) => state.filter);
   704→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
   705→  const createNote = useNotesStore((state) => state.createNote);
   706→  const bulkAddTag = useNotesStore((state) => state.bulkAddTag);
   707→  const bulkRemoveTag = useNotesStore((state) => state.bulkRemoveTag);
   708→
   709→  // Bulk operations state
   710→  const [selectionMode, setSelectionMode] = useState(false);
   711→  const [selectedNoteIds, setSelectedNoteIds] = useState<Set<string>>(new Set());
   712→  const [bulkTagDialogOpen, setBulkTagDialogOpen] = useState(false);
   713→  const [bulkTagAction, setBulkTagAction] = useState<'add' | 'remove' | null>(null);
   714→  const [bulkTagValue, setBulkTagValue] = useState('');
   715→
   716→  // Bulk operations handlers
   717→  const toggleSelectionMode = () => {
   718→    setSelectionMode(!selectionMode);
   719→    if (selectionMode) {
   720→      setSelectedNoteIds(new Set());
   721→    }
   722→  };
   723→
   724→  const toggleNoteSelection = (noteId: string) => {
   725→    setSelectedNoteIds((prev) => {
   726→      const next = new Set(prev);
   727→      if (next.has(noteId)) {
   728→        next.delete(noteId);
   729→      } else {
   730→        next.add(noteId);
   731→      }
   732→      return next;
   733→    });
   734→  };
   735→
   736→  const selectAll = () => {
   737→    const allIds = notes.map((n) => n.id);
   738→    setSelectedNoteIds(new Set(allIds));
   739→  };
   740→
   741→  const deselectAll = () => {
   742→    setSelectedNoteIds(new Set());
   743→  };
   744→
   745→  const handleBulkAddTag = () => {
   746→    setBulkTagAction('add');
   747→    setBulkTagDialogOpen(true);
   748→  };
   749→
   750→  const handleBulkRemoveTag = () => {
   751→    setBulkTagAction('remove');
   752→    setBulkTagDialogOpen(true);
   753→  };
   754→
   755→  const confirmBulkTagAction = (value: string) => {
   756→    if (!value.trim() || selectedNoteIds.size === 0) return;
   757→
   758→    if (bulkTagAction === 'add') {
   759→      bulkAddTag(Array.from(selectedNoteIds), value.trim());
   760→    } else if (bulkTagAction === 'remove') {
   761→      bulkRemoveTag(Array.from(selectedNoteIds), value.trim());
   762→    }
   763→
   764→    // Clear selection and close dialog
   765→    setBulkTagDialogOpen(false);
   766→    setBulkTagValue('');
   767→    setSelectedNoteIds(new Set());
   768→    setSelectionMode(false);
   769→  };
   770→
   771→  // Compute filtered/sorted notes with useMemo
   772→  const notes = useMemo(() => {
   773→    // Filter by folder
   774→    // If activeFolderId is null, show ALL notes (not just notes with null folderId)
   775→    let filtered = activeFolderId === null
   776→      ? Object.values(notesObj) // Show all notes when "All Notes" is selected
   777→      : Object.values(notesObj).filter((note) => note.folderId === activeFolderId);
   778→
   779→    // Filter by tags (AND logic - note must have ALL selected tags or their children)
   780→    if (activeTags.length > 0) {
   781→      filtered = filtered.filter((note) =>
   782→        activeTags.every((filterTag) =>
   783→          note.tags.some((noteTag) => tagMatchesFilter(noteTag, filterTag))
   784→        )
   785→      );
   786→    }
   787→
   788→    // Apply filter (archived, pinned, favorites, etc.)
   789→    switch (filter) {
   790→      case 'favorites':
   791→        filtered = filtered.filter((note) => note.isFavorite);
   792→        break;
   793→      case 'pinned':
   794→        filtered = filtered.filter((note) => note.isPinned);
   795→        break;
   796→      case 'archived':
   797→        filtered = filtered.filter((note) => note.isArchived);
   798→        break;
   799→      case 'unarchived':
   800→        filtered = filtered.filter((note) => !note.isArchived);
   801→        break;
   802→    }
   803→
   804→    // Sort notes
   805→    const sorted = [...filtered].sort((a, b) => {
   806→      let comparison = 0;
   807→      switch (sortConfig.field) {
   808→        case 'title':
   809→          comparison = a.title.localeCompare(b.title);
   810→          break;
   811→        case 'createdAt':
   812→          comparison = a.createdAt.getTime() - b.createdAt.getTime();
   813→          break;
   814→        case 'updatedAt':
   815→          comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   816→          break;
   817→      }
   818→      return sortConfig.order === 'asc' ? comparison : -comparison;
   819→    });
   820→
   821→    // Always pin pinned notes to top
   822→    return sorted.sort((a, b) => {
   823→      if (a.isPinned && !b.isPinned) return -1;
   824→      if (!a.isPinned && b.isPinned) return 1;
   825→      return 0;
   826→    });
   827→  }, [notesObj, activeFolderId, sortConfig, filter, activeTags]);
   828→
   829→  return (
   830→    <div className="flex-1 overflow-y-auto">
   831→      <div className="bento-card p-4 m-3">
   832→        {/* Notes header */}
   833→        <div className="flex items-center justify-between mb-4">
   834→          <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
