   841→              title="Export notes (Cmd+Shift+E)"
   842→            >
   843→              <FileDown className="w-4 h-4" />
   844→              Export
   845→            </button>
   846→            <button
   847→              onClick={toggleSelectionMode}
   848→              className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all duration-200 ${
   849→                selectionMode
   850→                  ? 'bg-accent-cyan/20 dark:bg-accent-magenta/20 text-accent-cyan dark:text-accent-magenta'
   851→                  : 'border border-border-light dark:border-border-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   852→              }`}
   853→            >
   854→              {selectionMode ? 'Cancel Selection' : 'Select Notes'}
   855→            </button>
   856→            <button
   857→              onClick={onOpenTemplateLibrary}
   858→              className="px-3 py-1.5 bg-accent-purple text-white rounded-lg hover:bg-accent-purple-hover transition-all duration-200 text-sm font-medium flex items-center gap-1"
   859→              title="Create note from template"
   860→            >
   861→              <Sparkles className="w-4 h-4" />
   862→              From Template
   863→            </button>
   864→            <button
   865→              onClick={() => createNote({ folderId: activeFolderId })}
   866→              className="px-3 py-1.5 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-200 text-sm font-medium"
   867→            >
   868→              + New Note
   869→            </button>
   870→          </div>
   871→        </div>
   872→
   873→        {/* Bulk Operations Toolbar */}
   874→        {selectionMode && selectedNoteIds.size > 0 && (
   875→          <div className="mb-4 p-3 rounded-lg bg-accent-blue/10 dark:bg-accent-blue/20 border border-accent-blue/30">
   876→            <div className="flex items-center justify-between">
   877→              <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
   878→                {selectedNoteIds.size} note{selectedNoteIds.size !== 1 ? 's' : ''} selected
   879→              </span>
   880→              <div className="flex items-center gap-2">
   881→                <button
   882→                  onClick={selectAll}
   883→                  className="px-2 py-1 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors text-text-light-secondary dark:text-text-dark-secondary"
   884→                >
   885→                  Select All
   886→                </button>
   887→                <button
   888→                  onClick={deselectAll}
   889→                  className="px-2 py-1 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors text-text-light-secondary dark:text-text-dark-secondary"
   890→                >
   891→                  Deselect All
   892→                </button>
   893→                <button
   894→                  onClick={handleBulkAddTag}
   895→                  className="px-3 py-1 text-xs font-medium rounded bg-accent-blue text-white hover:bg-accent-blue-hover transition-colors"
   896→                >
   897→                  Add Tag
   898→                </button>
   899→                <button
   900→                  onClick={handleBulkRemoveTag}
   901→                  className="px-3 py-1 text-xs font-medium rounded bg-red-500/20 text-red-500 hover:bg-red-500/30 transition-colors"
   902→                >
   903→                  Remove Tag
   904→                </button>
   905→              </div>
   906→            </div>
   907→          </div>
   908→        )}
   909→
   910→      {/* Notes list */}
   911→      <div className="space-y-3">
   912→        {notes.map((note) => (
   913→          <NoteListItem
   914→            key={note.id}
   915→            note={note}
   916→            isActive={note.id === activeNoteId}
   917→            isSelectionMode={selectionMode}
   918→            isSelected={selectedNoteIds.has(note.id)}
   919→            onToggleSelection={toggleNoteSelection}
   920→          />
   921→        ))}
   922→      </div>
   923→
   924→      {/* Empty state */}
   925→      {notes.length === 0 && (
   926→        <div className="text-center py-16 animate-fade-in">
   927→          <div className="flex justify-center mb-6">
   928→            <div className="p-6 bg-gradient-to-br from-accent-magenta/10 to-accent-cyan/10 dark:from-accent-cyan/10 dark:to-accent-magenta/10 rounded-2xl">
   929→              <FileText className="w-16 h-16 text-accent-cyan dark:text-accent-magenta" />
   930→            </div>
   931→          </div>
   932→          <h3 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary mb-3">
   933→            {activeTags.length > 0 ? 'No notes match these tags' : 'No notes in this folder'}
   934→          </h3>
   935→          <p className="text-text-light-secondary dark:text-text-dark-secondary mb-2 max-w-sm mx-auto">
   936→            {activeTags.length > 0
   937→              ? 'Try removing some tags or create a new note'
   938→              : 'Start capturing your thoughts, ideas, and knowledge'}
   939→          </p>
   940→          <p className="text-sm text-text-light-tertiary dark:text-text-dark-tertiary mb-6">
   941→            Tip: Use <kbd className="px-2 py-1 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded text-xs font-mono">Cmd+N</kbd> to create notes quickly
   942→          </p>
   943→          <button
   944→            onClick={() => createNote({ folderId: activeFolderId })}
   945→            className="px-6 py-3 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-standard font-medium inline-flex items-center gap-2"
   946→          >
   947→            <FileText className="w-5 h-5" />
   948→            Create Your First Note
   949→          </button>
   950→        </div>
   951→      )}
   952→      </div>
   953→
   954→      {/* Bulk Tag Dialog */}
   955→      {bulkTagDialogOpen && (
   956→        <PromptDialog
   957→          isOpen={true}
   958→          onClose={() => {
   959→            setBulkTagDialogOpen(false);
   960→            setBulkTagValue('');
   961→          }}
   962→          onConfirm={confirmBulkTagAction}
   963→          title={bulkTagAction === 'add' ? 'Add Tag to Selected Notes' : 'Remove Tag from Selected Notes'}
   964→          message={
   965→            bulkTagAction === 'add'
   966→              ? `Enter tag name to add to ${selectedNoteIds.size} note${selectedNoteIds.size !== 1 ? 's' : ''}:`
   967→              : `Enter tag name to remove from ${selectedNoteIds.size} note${selectedNoteIds.size !== 1 ? 's' : ''}:`
   968→          }
   969→          defaultValue={bulkTagValue}
   970→          placeholder="Tag name"
   971→          confirmText={bulkTagAction === 'add' ? 'Add Tag' : 'Remove Tag'}
   972→        />
   973→      )}
   974→    </div>
   975→  );
   976→};
   977→
   978→/**
   979→ * Notes Page Component
   980→ */
   981→export const Notes: React.FC = () => {
   982→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
   983→  const getOrCreateDailyNote = useNotesStore((state) => state.getOrCreateDailyNote);
   984→  const dailyNotesEnabled = useSettingsStore((state) => state.dailyNotes.enabled);
   985→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
   986→  const [sidebarWidth, setSidebarWidth] = useState(320);
   987→  const [isResizing, setIsResizing] = useState(false);
   988→  const [showCalendar, setShowCalendar] = useState(false);
   989→  const sidebarRef = useRef<HTMLDivElement>(null);
   990→  const [searchParams, setSearchParams] = useSearchParams();
   991→  const [blockId, setBlockId] = useState<string | undefined>();
   992→
   993→  // Tag filtering state
   994→  const [activeTags, setActiveTags] = useState<string[]>([]);
   995→  const [showTagManager, setShowTagManager] = useState(false);
   996→
   997→  // Template Library state
   998→  const [showTemplateLibrary, setShowTemplateLibrary] = useState(false);
   999→  const [showTitlePrompt, setShowTitlePrompt] = useState(false);
  1000→  const [selectedTemplate, setSelectedTemplate] = useState<NoteTemplate | null>(null);
  1001→  const [titleInput, setTitleInput] = useState('');
  1002→
  1003→  // Export Modal state
  1004→  const [showExportModal, setShowExportModal] = useState(false);
  1005→
  1006→  // Get store actions
  1007→  const createNote = useNotesStore((state) => state.createNote);
  1008→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
  1009→
  1010→  const handleAddTag = (tag: string) => {
  1011→    if (!activeTags.includes(tag)) {
  1012→      setActiveTags([...activeTags, tag]);
  1013→    }
  1014→  };
  1015→
  1016→  const handleRemoveTag = (tag: string) => {
  1017→    setActiveTags(activeTags.filter((t) => t !== tag));
  1018→  };
  1019→
  1020→  const handleClearAllTags = () => {
  1021→    setActiveTags([]);
  1022→  };
  1023→
  1024→  // Template selection handlers
  1025→  const handleSelectTemplate = (template: NoteTemplate) => {
  1026→    // Check if template contains {title} variable
  1027→    const variables = extractTemplateVariables(template.description);
  1028→    if (variables.includes('title')) {
  1029→      // Prompt user for title
  1030→      setSelectedTemplate(template);
  1031→      setTitleInput('');
  1032→      setShowTitlePrompt(true);
  1033→      setShowTemplateLibrary(false);
  1034→    } else {
  1035→      // Create note immediately with variable substitution
  1036→      createNoteFromTemplate(template);
  1037→    }
  1038→  };
  1039→
  1040→  const createNoteFromTemplate = (template: NoteTemplate, customTitle?: string) => {
  1041→    // Substitute template variables
  1042→    const context = {
  1043→      title: customTitle,
  1044→      userName: 'User', // Could be fetched from settings in future
  1045→    };
  1046→    const processedContent = substituteTemplateVariables(template.description, context);
  1047→
  1048→    // Create note with template content and tags
  1049→    const newNote = createNote({
  1050→      folderId: activeFolderId,
  1051→      title: customTitle || template.name,
  1052→      contentText: processedContent,
  1053→      tags: template.defaultTags || [],
  1054→      icon: template.icon,
  1055→    });
  1056→
  1057→    log.info('Created note from template', {
  1058→      templateId: template.id,
  1059→      noteId: newNote.id,
  1060→      title: newNote.title,
  1061→    });
  1062→  };
  1063→
  1064→  const handleConfirmTitle = (title: string) => {
  1065→    if (selectedTemplate && title.trim()) {
  1066→      createNoteFromTemplate(selectedTemplate, title.trim());
  1067→      setShowTitlePrompt(false);
  1068→      setSelectedTemplate(null);
  1069→      setTitleInput('');
  1070→    }
  1071→  };
  1072→
  1073→  const handleCancelTitle = () => {
  1074→    setShowTitlePrompt(false);
  1075→    setSelectedTemplate(null);
  1076→    setTitleInput('');
  1077→  };
  1078→
  1079→  useEffect(() => {
  1080→    document.title = 'Notes - Neuman Brain';
  1081→    log.debug('Notes page loaded');
  1082→
  1083→    // Keyboard shortcut for export (Cmd/Ctrl+Shift+E)
  1084→    const handleKeyDown = (e: KeyboardEvent) => {
  1085→      if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key === 'E') {
  1086→        e.preventDefault();
  1087→        setShowExportModal(true);
  1088→      }
  1089→    };
  1090→
  1091→    window.addEventListener('keydown', handleKeyDown);
  1092→    return () => window.removeEventListener('keydown', handleKeyDown);
  1093→  }, []);
  1094→
  1095→  // Handle ?daily=true query parameter to open today's daily note
  1096→  useEffect(() => {
  1097→    if (searchParams.get('daily') === 'true' && dailyNotesEnabled) {
  1098→      const today = new Date();
  1099→      getOrCreateDailyNote(today); // Auto-selects the note by setting activeNoteId
  1100→      // Remove the query parameter after handling it
  1101→      searchParams.delete('daily');
  1102→      setSearchParams(searchParams, { replace: true });
  1103→    }
  1104→  }, [searchParams, dailyNotesEnabled, getOrCreateDailyNote, setSearchParams]);
  1105→
  1106→  // Extract block ID from URL hash (#block-id)
  1107→  useEffect(() => {
  1108→    const handleHashChange = () => {
  1109→      const hash = window.location.hash;
  1110→      if (hash && hash.startsWith('#')) {
  1111→        const id = hash.substring(1); // Remove # prefix
  1112→        setBlockId(id);
  1113→      } else {
  1114→        setBlockId(undefined);
  1115→      }
  1116→    };
  1117→
  1118→    // Set initial block ID
  1119→    handleHashChange();
  1120→
  1121→    // Listen for hash changes
  1122→    window.addEventListener('hashchange', handleHashChange);
  1123→    return () => window.removeEventListener('hashchange', handleHashChange);
  1124→  }, []);
  1125→
  1126→  // Handle sidebar resize
  1127→  const handleMouseDown = (e: React.MouseEvent) => {
  1128→    e.preventDefault();
  1129→    setIsResizing(true);
  1130→  };
  1131→
  1132→  useEffect(() => {
  1133→    const handleMouseMove = (e: MouseEvent) => {
  1134→      if (!isResizing) return;
  1135→      const newWidth = Math.max(200, Math.min(500, e.clientX - 72)); // 72px is sidebar offset
  1136→      setSidebarWidth(newWidth);
  1137→    };
  1138→
  1139→    const handleMouseUp = () => {
  1140→      setIsResizing(false);
  1141→    };
  1142→
  1143→    if (isResizing) {
  1144→      document.addEventListener('mousemove', handleMouseMove);
  1145→      document.addEventListener('mouseup', handleMouseUp);
  1146→      document.body.style.cursor = 'ew-resize';
  1147→      document.body.style.userSelect = 'none';
  1148→    }
  1149→
  1150→    return () => {
  1151→      document.removeEventListener('mousemove', handleMouseMove);
  1152→      document.removeEventListener('mouseup', handleMouseUp);
  1153→      document.body.style.cursor = '';
  1154→      document.body.style.userSelect = '';
  1155→    };
  1156→  }, [isResizing]);
  1157→
  1158→  return (
  1159→    <div className="notes-page">
  1160→      {/* Page Header */}
  1161→      <PageHeader />
  1162→
  1163→      {/* Notes Content */}
  1164→      <div className="h-[calc(100vh-280px)] flex relative">
  1165→        {/* Left Sidebar - Folders + Notes List */}
  1166→        <AnimatePresence>
  1167→        {!isSidebarCollapsed && (
  1168→          <motion.div
  1169→            ref={sidebarRef}
  1170→            initial={{ width: 0, opacity: 0 }}
  1171→            animate={{ width: sidebarWidth, opacity: 1 }}
  1172→            exit={{ width: 0, opacity: 0 }}
  1173→            transition={{ duration: 0.2 }}
  1174→            className="flex-shrink-0 border-r border-border-light dark:border-border-dark bg-transparent flex flex-col relative"
  1175→            style={{ width: sidebarWidth }}
  1176→          >
  1177→            <FolderSidebar
  1178→              activeTags={activeTags}
  1179→              onAddTag={handleAddTag}
  1180→              onRemoveTag={handleRemoveTag}
  1181→              onClearAllTags={handleClearAllTags}
  1182→              onOpenTagManager={() => setShowTagManager(true)}
  1183→            />
  1184→            <NotesList
  1185→              activeTags={activeTags}
  1186→              onOpenTemplateLibrary={() => setShowTemplateLibrary(true)}
  1187→              onOpenExportModal={() => setShowExportModal(true)}
  1188→            />
  1189→
  1190→            {/* Collapse button - inside sidebar at top right */}
  1191→            <button
  1192→              onClick={() => setIsSidebarCollapsed(true)}
  1193→              className="absolute top-4 right-2 z-20 p-1.5 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button hover:bg-surface-light-elevated dark:hover:bg-neutral-800 transition-all duration-200"
  1194→              title="Collapse Sidebar"
  1195→            >
  1196→              <svg className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
  1197→                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 19l-7-7 7-7m8 14l-7-7 7-7" />
  1198→              </svg>
  1199→            </button>
  1200→
  1201→            {/* Resize handle */}
  1202→            <div
  1203→              onMouseDown={handleMouseDown}
  1204→              className={`absolute right-0 top-0 bottom-0 w-1 cursor-ew-resize hover:bg-accent-blue/50 transition-colors ${isResizing ? 'bg-accent-blue' : ''}`}
  1205→              title="Drag to resize"
  1206→            />
  1207→          </motion.div>
  1208→        )}
  1209→      </AnimatePresence>
  1210→
  1211→        {/* Sidebar expand button - shown when collapsed */}
  1212→        {isSidebarCollapsed && (
  1213→          <button
  1214→            onClick={() => setIsSidebarCollapsed(false)}
  1215→            className="flex-shrink-0 p-2 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-r-lg hover:bg-surface-light-elevated dark:hover:bg-neutral-800 transition-all duration-200 self-start mt-4 ml-2"
  1216→            title="Expand Sidebar"
  1217→          >
  1218→            <svg className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
  1219→              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 5l7 7-7 7M5 5l7 7-7 7" />
  1220→            </svg>
  1221→          </button>
  1222→        )}
  1223→
  1224→        {/* Spacer between sidebar and editor */}
  1225→        {!isSidebarCollapsed && <div className="w-4 flex-shrink-0" />}
  1226→
  1227→      {/* Center - Editor or Calendar */}
  1228→      <div className="flex-1 overflow-hidden flex flex-col">
  1229→        {/* View Toggle (only shown when no note selected and daily notes enabled) */}
  1230→        {!activeNoteId && dailyNotesEnabled && (
  1231→          <div className="flex gap-2 mb-4 px-4">
  1232→            <button
  1233→              onClick={() => setShowCalendar(false)}
  1234→              className={`px-4 py-2 rounded-button text-sm font-medium transition-all ${
  1235→                !showCalendar
  1236→                  ? 'bg-accent-magenta dark:bg-accent-cyan text-white'
  1237→                  : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark'
  1238→              }`}
  1239→            >
  1240→              Notes
  1241→            </button>
  1242→            <button
  1243→              onClick={() => setShowCalendar(true)}
  1244→              className={`flex items-center gap-2 px-4 py-2 rounded-button text-sm font-medium transition-all ${
  1245→                showCalendar
  1246→                  ? 'bg-accent-magenta dark:bg-accent-cyan text-white'
  1247→                  : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark'
  1248→              }`}
  1249→            >
  1250→              <CalendarIcon className="w-4 h-4" />
  1251→              Daily Notes Calendar
  1252→            </button>
  1253→          </div>
  1254→        )}
  1255→
  1256→        {/* Main Content Area */}
  1257→        <div className="flex-1 overflow-hidden border border-border-light dark:border-border-dark rounded-lg">
  1258→          {activeNoteId ? (
  1259→            <NotesEditor noteId={activeNoteId} blockId={blockId} />
  1260→          ) : showCalendar && dailyNotesEnabled ? (
  1261→            <div className="h-full overflow-auto p-6">
  1262→              <DailyNotesCalendar />
  1263→            </div>
  1264→          ) : (
  1265→            <NotesEditorEmpty />
  1266→          )}
  1267→        </div>
  1268→      </div>
  1269→
  1270→      {/* Right Sidebar - Metadata (Future) */}
  1271→      {/* TODO: Add note metadata panel */}
  1272→    </div>
  1273→
  1274→      {/* Tag Manager Modal */}
  1275→      <TagManager
  1276→        isOpen={showTagManager}
  1277→        onClose={() => setShowTagManager(false)}
  1278→      />
  1279→
  1280→      {/* Template Library Modal */}
  1281→      <TemplateLibrary
  1282→        isOpen={showTemplateLibrary}
  1283→        onClose={() => setShowTemplateLibrary(false)}
  1284→        onSelect={handleSelectTemplate}
  1285→      />
  1286→
  1287→      {/* Title Prompt Modal */}
  1288→      {showTitlePrompt && selectedTemplate && (
  1289→        <PromptDialog
  1290→          isOpen={true}
  1291→          onClose={handleCancelTitle}
  1292→          onConfirm={handleConfirmTitle}
  1293→          title="Enter Note Title"
  1294→          message={`Create a note from template "${selectedTemplate.name}". Please enter a title:`}
  1295→          defaultValue={titleInput}
  1296→          placeholder="Note title"
  1297→          confirmText="Create Note"
  1298→        />
  1299→      )}
  1300→
  1301→      {/* Export Notes Modal */}
  1302→      <ExportNotesModal
  1303→        isOpen={showExportModal}
  1304→        onClose={() => setShowExportModal(false)}
  1305→      />
  1306→    </div>
  1307→  );
  1308→};
