    81→
    82→    // Sort
    83→    result = [...result].sort((a, b) => {
    84→      let comparison = 0;
    85→      switch (sortField) {
    86→        case 'title':
    87→          comparison = a.title.localeCompare(b.title);
    88→          break;
    89→        case 'createdAt':
    90→          comparison = a.createdAt.getTime() - b.createdAt.getTime();
    91→          break;
    92→        case 'updatedAt':
    93→          comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
    94→          break;
    95→        case 'visitCount':
    96→          comparison = a.visitCount - b.visitCount;
    97→          break;
    98→      }
    99→      return sortDirection === 'asc' ? comparison : -comparison;
   100→    });
   101→
   102→    return result;
