   643→            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
   644→              {displayedLinks.map((link) => (
   645→                <LinkCard
   646→                  key={link.id}
   647→                  link={link}
   648→                  isSelected={selectedLinkIds.has(link.id)}
   649→                  onToggleSelect={() => toggleLinkSelection(link.id)}
   650→                  onToggleFavorite={() => toggleFavorite(link.id)}
   651→                  onToggleArchive={() => toggleArchived(link.id)}
   652→                />
   653→              ))}
   654→            </div>
   655→          ) : (
   656→            /* List View */
   657→            <div className="space-y-2">
   658→              {displayedLinks.map((link) => (
   659→                <LinkListItem
   660→                  key={link.id}
   661→                  link={link}
   662→                  isSelected={selectedLinkIds.has(link.id)}
   663→                  onToggleSelect={() => toggleLinkSelection(link.id)}
   664→                  onToggleFavorite={() => toggleFavorite(link.id)}
   665→                  onToggleArchive={() => toggleArchived(link.id)}
   666→                />
   667→              ))}
   668→            </div>
   669→          )}
   670→        </div>
   671→      )}
   672→        </div>
   673→      </div>
   674→    </div>
   675→  );
   676→};
   677→
   678→// ============================================================================
   679→// Link Card Component (Grid View)
   680→// ============================================================================
   681→
   682→interface LinkCardProps {
   683→  link: Link;
   684→  isSelected: boolean;
   685→  onToggleSelect: () => void;
   686→  onToggleFavorite: () => void;
   687→  onToggleArchive: () => void;
   688→}
   689→
   690→const LinkCard: React.FC<LinkCardProps> = ({
   691→  link,
   692→  isSelected,
   693→  onToggleSelect,
   694→  onToggleFavorite,
   695→  onToggleArchive,
   696→}) => {
   697→  const faviconUrl = `https://www.google.com/s2/favicons?domain=${new URL(link.url).hostname}&sz=32`;
   698→
   699→  return (
   700→    <div
   701→      className={`
   702→        p-4 rounded-card bg-surface-light dark:bg-surface-dark-elevated
   703→        border transition-all duration-200
   704→        ${isSelected
   705→          ? 'border-accent-blue ring-2 ring-accent-blue/20'
   706→          : 'border-border-light dark:border-border-dark hover:border-accent-blue/50'
   707→        }
   708→      `}
   709→    >
   710→      {/* Header */}
   711→      <div className="flex items-start gap-3 mb-3">
   712→        <input
   713→          type="checkbox"
   714→          checked={isSelected}
   715→          onChange={onToggleSelect}
   716→          className="mt-1 w-4 h-4 rounded border-border-light dark:border-border-dark"
   717→        />
   718→        <img
   719→          src={faviconUrl}
   720→          alt=""
   721→          className="w-6 h-6 rounded flex-shrink-0"
   722→          onError={(e) => {
   723→            (e.target as HTMLImageElement).src = 'data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="%236b7280"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-1 17.93c-3.95-.49-7-3.85-7-7.93 0-.62.08-1.21.21-1.79L9 15v1c0 1.1.9 2 2 2v1.93zm6.9-2.54c-.26-.81-1-1.39-1.9-1.39h-1v-3c0-.55-.45-1-1-1H8v-2h2c.55 0 1-.45 1-1V7h2c1.1 0 2-.9 2-2v-.41c2.93 1.19 5 4.06 5 7.41 0 2.08-.8 3.97-2.1 5.39z"/></svg>';
   724→          }}
   725→        />
   726→        <div className="flex-1 min-w-0">
   727→          <a
   728→            href={link.url}
   729→            target="_blank"
   730→            rel="noopener noreferrer"
   731→            className="block font-medium text-text-light-primary dark:text-text-dark-primary
   732→                       hover:text-accent-blue truncate"
   733→          >
   734→            {link.title}
   735→          </a>
   736→          <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary truncate">
   737→            {new URL(link.url).hostname}
   738→          </p>
   739→        </div>
   740→      </div>
   741→
   742→      {/* Category & Tags */}
   743→      {(link.category || link.tags.length > 0) && (
   744→        <div className="flex flex-wrap gap-1 mb-3">
   745→          {link.category && (
   746→            <span className="px-2 py-0.5 text-xs rounded-full bg-accent-blue/10 text-accent-blue">
   747→              {link.category}
   748→            </span>
   749→          )}
   750→          {link.tags.slice(0, 2).map((tag) => (
   751→            <span
   752→              key={tag}
   753→              className="px-2 py-0.5 text-xs rounded-full bg-neutral-100 dark:bg-neutral-800
   754→                         text-text-light-secondary dark:text-text-dark-secondary"
   755→            >
   756→              {tag}
   757→            </span>
   758→          ))}
   759→          {link.tags.length > 2 && (
   760→            <span className="px-2 py-0.5 text-xs text-text-light-secondary dark:text-text-dark-secondary">
   761→              +{link.tags.length - 2}
   762→            </span>
   763→          )}
   764→        </div>
   765→      )}
   766→
   767→      {/* Actions */}
   768→      <div className="flex items-center gap-2 pt-2 border-t border-border-light dark:border-border-dark">
   769→        <button
   770→          onClick={onToggleFavorite}
   771→          className={`p-1.5 rounded transition-colors ${link.isFavorite
   772→              ? 'text-status-warning'
   773→              : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-status-warning'
   774→            }`}
   775→          title={link.isFavorite ? 'Remove from favorites' : 'Add to favorites'}
   776→        >
   777→          {link.isFavorite ? '★' : '☆'}
   778→        </button>
   779→        <button
   780→          onClick={onToggleArchive}
   781→          className="p-1.5 rounded text-text-light-secondary dark:text-text-dark-secondary
   782→                     hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
   783→          title={link.isArchived ? 'Unarchive' : 'Archive'}
   784→        >
   785→          📥
   786→        </button>
   787→        <div className="flex-1" />
   788→        <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   789→          {link.visitCount > 0 && `${link.visitCount} visits`}
   790→        </span>
   791→      </div>
   792→    </div>
   793→  );
   794→};
   795→
   796→// ============================================================================
   797→// Link List Item Component (List View)
   798→// ============================================================================
   799→
   800→const LinkListItem: React.FC<LinkCardProps> = ({
   801→  link,
   802→  isSelected,
   803→  onToggleSelect,
   804→  onToggleFavorite,
   805→  onToggleArchive,
   806→}) => {
   807→  const faviconUrl = `https://www.google.com/s2/favicons?domain=${new URL(link.url).hostname}&sz=16`;
   808→
   809→  return (
   810→    <div
   811→      className={`
   812→        flex items-center gap-4 px-4 py-3 rounded-button
   813→        bg-surface-light dark:bg-surface-dark-elevated
   814→        border transition-all duration-200
   815→        ${isSelected
   816→          ? 'border-accent-blue ring-2 ring-accent-blue/20'
   817→          : 'border-border-light dark:border-border-dark hover:border-accent-blue/50'
   818→        }
   819→      `}
   820→    >
   821→      <input
   822→        type="checkbox"
   823→        checked={isSelected}
   824→        onChange={onToggleSelect}
   825→        className="w-4 h-4 rounded border-border-light dark:border-border-dark"
   826→      />
   827→
   828→      <img
   829→        src={faviconUrl}
   830→        alt=""
   831→        className="w-4 h-4 rounded flex-shrink-0"
   832→        onError={(e) => {
   833→          (e.target as HTMLImageElement).style.display = 'none';
   834→        }}
   835→      />
   836→
   837→      <div className="flex-1 min-w-0">
   838→        <a
   839→          href={link.url}
   840→          target="_blank"
   841→          rel="noopener noreferrer"
   842→          className="font-medium text-text-light-primary dark:text-text-dark-primary
   843→                     hover:text-accent-blue truncate block"
   844→        >
   845→          {link.title}
   846→        </a>
   847→      </div>
   848→
   849→      <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary truncate max-w-[200px]">
   850→        {new URL(link.url).hostname}
   851→      </span>
   852→
   853→      {link.category && (
   854→        <span className="px-2 py-0.5 text-xs rounded-full bg-accent-blue/10 text-accent-blue">
   855→          {link.category}
   856→        </span>
   857→      )}
   858→
   859→      <button
   860→        onClick={onToggleFavorite}
   861→        className={`p-1.5 rounded transition-colors ${link.isFavorite
   862→            ? 'text-status-warning'
   863→            : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-status-warning'
   864→          }`}
   865→        title={link.isFavorite ? 'Remove from favorites' : 'Add to favorites'}
   866→      >
   867→        {link.isFavorite ? '★' : '☆'}
   868→      </button>
