interface LinkCardProps {
  link: Link;
  isSelected: boolean;
  onToggleSelect: () => void;
  onToggleFavorite: () => void;
  onToggleArchive: () => void;
}

const LinkCard: React.FC<LinkCardProps> = ({
  link,
  isSelected,
  onToggleSelect,
  onToggleFavorite,
  onToggleArchive,
