            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mt-1">
              {sortedDiagrams.length} {sortedDiagrams.length === 1 ? 'diagram' : 'diagrams'}
            </p>
          </div>

          <div className="flex items-center gap-3">
            {/* Search */}
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-text-light-tertiary dark:text-text-dark-tertiary" />
              <input
                type="text"
                placeholder="Search diagrams..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-9 pr-3 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
              />
            </div>

            {/* View mode toggle */}
            <div className="flex gap-1 bg-surface-light dark:bg-surface-dark rounded-lg p-1">
              <button
                onClick={() => setViewMode('grid')}
                className={`p-2 rounded ${
                  viewMode === 'grid'
                    ? 'bg-accent-blue dark:bg-accent-blue text-white'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
                }`}
                aria-label="Grid view"
              >
                <Grid3x3 className="w-4 h-4" />
              </button>
              <button
                onClick={() => setViewMode('list')}
                className={`p-2 rounded ${
                  viewMode === 'list'
                    ? 'bg-primary-light dark:bg-primary-dark text-white'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-hover-light dark:hover:bg-surface-hover-dark'
                }`}
                aria-label="List view"
              >
                <List className="w-4 h-4" />
              </button>
            </div>

            {/* Create buttons */}
            <button
              onClick={() => setShowTemplateGallery(true)}
              className="flex items-center gap-2 px-4 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark text-text-light-primary dark:text-text-dark-primary rounded-lg hover:bg-surface-hover-light dark:hover:bg-surface-hover-dark transition-colors"
            >
              <FileText className="w-4 h-4" />
              From Template
            </button>
            <button
              onClick={handleCreateDiagram}
              className="flex items-center gap-2 px-4 py-2 bg-primary-light dark:bg-primary-dark text-white rounded-lg hover:opacity-90 transition-opacity"
            >
              <Plus className="w-4 h-4" />
              New Diagram
            </button>
          </div>
        </header>

        {/* Template Gallery Modal */}
        <TemplateGallery
          isOpen={showTemplateGallery}
          onClose={() => setShowTemplateGallery(false)}
          onSelectTemplate={handleCreateFromTemplate}
        />

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6">
          {sortedDiagrams.length === 0 ? (
            // Empty state
            <div className="flex flex-col items-center justify-center h-full text-center">
              <div className="w-24 h-24 mb-4 rounded-full bg-surface-light dark:bg-surface-dark flex items-center justify-center">
                <Grid3x3 className="w-12 h-12 text-text-light-tertiary dark:text-text-dark-tertiary" />
              </div>
              <h2 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
                {searchQuery ? 'No diagrams found' : 'No diagrams yet'}
              </h2>
              <p className="text-text-light-secondary dark:text-text-dark-secondary mb-6 max-w-md">
                {searchQuery
                  ? 'Try adjusting your search query'
                  : 'Create your first diagram to visualize ideas, plan projects, or document workflows'}
              </p>
              {!searchQuery && (
                <button
                  onClick={handleCreateDiagram}
                  className="flex items-center gap-2 px-6 py-3 bg-primary-light dark:bg-primary-dark text-white rounded-lg hover:opacity-90 transition-opacity"
                >
                  <Plus className="w-5 h-5" />
                  Create Your First Diagram
                </button>
              )}
            </div>
          ) : viewMode === 'grid' ? (
            // Grid view
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
              {sortedDiagrams.map((diagram) => (
                <DiagramCard
                  key={diagram.id}
                  diagram={diagram}
                  onOpen={() => handleOpenDiagram(diagram.id)}
                  onDelete={() => handleDeleteDiagram(diagram.id)}
                  onDuplicate={() => handleDuplicateDiagram(diagram.id)}
                />
              ))}
            </div>
          ) : (
            // List view
            <div className="space-y-2">
              {sortedDiagrams.map((diagram) => (
                <DiagramListItem
                  key={diagram.id}
                  diagram={diagram}
                  onOpen={() => handleOpenDiagram(diagram.id)}
                  onDelete={() => handleDeleteDiagram(diagram.id)}
                  onDuplicate={() => handleDuplicateDiagram(diagram.id)}
                />
              ))}
            </div>
          )}
        </div>
      </main>
    </StoreErrorBoundary>
  );
}

